      {s>0&&<button onClick={function(){setS(s-1)}} style={{padding:"8px 16px",borderRadius:8,border:"1px solid "+Bdr,background:"#fff",color:Tx2,fontWeight:600,fontSize:12,cursor:"pointer",fontFamily:F}}>Back</button>}
      {s<steps.length-1?<button onClick={function(){setS(s+1)}} style={{padding:"8px 20px",borderRadius:8,border:"none",background:Dk,color:"#fff",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:F}}>Next</button>:<button onClick={props.onDone} style={{padding:"8px 20px",borderRadius:8,border:"none",background:P,color:"#fff",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:F}}>Get Started</button>}
