/* ── Components ── */
function Sparkline(props){var c=props.color||P;var pts=useMemo(function(){var a=[];for(var i=0;i<12;i++)a.push(Math.random()*.5+.2+(i/12)*.4);return a},[]);var h=22,w=64;var mx=Math.max.apply(null,pts),mn=Math.min.apply(null,pts);var d="M"+pts.map(function(v,i){return(i/11*w).toFixed(1)+","+(h-(v-mn)/(mx-mn||1)*h).toFixed(1)}).join(" L");return<svg width={w} height={h} style={{display:"block"}}><path d={d+" L"+w+","+h+" L0,"+h+" Z"} fill={c} opacity=".08"/><path d={d} fill="none" stroke={c} strokeWidth="1.5" strokeLinecap="round"/></svg>}

function ScoreBtn(props){return<div style={{display:"flex",gap:3}}>{[1,2,3,4,5].map(function(n){return<button key={n} onClick={function(){props.onChange(n)}} style={{width:32,height:32,borderRadius:8,border:props.value===n?"2px solid "+props.color:"1.5px solid "+Bdr,background:props.value===n?props.color:"#fff",color:props.value===n?"#fff":Tx3,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:F,transition:"all .12s"}}>{n}</button>})}</div>}

function Gauge(props){var score=props.score;var q=getQ(score),pct=Math.min(score/5,1)*100;return<div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:4}}><div style={{fontSize:24,fontWeight:800,color:Tx,lineHeight:1,letterSpacing:"-0.02em"}}>{score>0?score.toFixed(1):"—"}<span style={{fontSize:11,fontWeight:500,color:Tx3}}> /5</span></div><div style={{width:"100%",position:"relative"}}><div style={{display:"flex",height:6,borderRadius:20,overflow:"hidden",background:Surf}}><div style={{flex:50,background:"#fca5a5"}}/><div style={{flex:26,background:"#fcd34d"}}/><div style={{flex:24,background:"#86efac"}}/></div>{score>0&&<div style={{position:"absolute",top:-1,left:pct+"%",transform:"translateX(-50%)",transition:"left .4s"}}><div style={{width:2,height:8,background:Tx,borderRadius:1}}/></div>}</div>{q&&<span style={{padding:"2px 10px",borderRadius:6,fontSize:10,fontWeight:700,background:q.bg2,color:q.color}}>{q.full}</span>}</div>}

function StagePill(props){var s=props.stage,sm=props.small;return<span style={{display:"inline-flex",alignItems:"center",gap:3,padding:sm?"1px 6px":"2px 8px",borderRadius:6,fontSize:sm?9:10,fontWeight:600,color:STAGE_C[s],background:STAGE_C[s]+"12",letterSpacing:".02em"}}><span style={{fontSize:sm?8:9}}>{STAGE_IC[s]}</span>{s}</span>}

function Waterfall(props){var ref=useRef(),cRef=useRef();var[ww,setWW]=useState(500);useEffect(function(){var ro=new ResizeObserver(function(e){var w=e[0]&&e[0].contentRect.width;if(w>50)setWW(w)});if(cRef.current)ro.observe(cRef.current);return function(){ro.disconnect()}},[]);useEffect(function(){if(!ref.current||!props.total)return;var svg=d3.select(ref.current);svg.selectAll("*").remove();var steps=[{l:"Active",v:props.total,t:"total"},{l:"Non-prio",v:-props.nonPrio,t:"dec"},{l:"Priority",v:props.prio,t:"sub"},{l:"Unmapped",v:-props.notMapped,t:"dec"},{l:"P2",v:-props.p2,t:"dec"},{l:"P1",v:props.p1,t:"sub"},{l:"Public",v:-props.pub,t:"dec"},{l:"Private",v:props.priv,t:"fin"}];var h=180,m={top:16,right:8,bottom:36,left:36},iw=ww-m.left-m.right,ih=h-m.top-m.bottom;var g=svg.attr("viewBox","0 0 "+ww+" "+h).append("g").attr("transform","translate("+m.left+","+m.top+")");var x=d3.scaleBand().domain(steps.map(function(d){return d.l})).range([0,iw]).padding(.2);var y=d3.scaleLinear().domain([0,props.total*1.12]).range([ih,0]);var run=0;var bars=steps.map(function(s){var y0,y1;if(s.t==="total"||s.t==="sub"||s.t==="fin"){y0=0;y1=Math.abs(s.v);run=Math.abs(s.v)}else{y1=run;y0=run+s.v;run=y0}return{l:s.l,v:s.v,t:s.t,y0:y0,y1:y1}});for(var i=0;i<bars.length-1;i++){var c=bars[i],n=bars[i+1];var fy=c.t==="dec"?y(c.y0):y(c.y1);g.append("line").attr("x1",x(c.l)+x.bandwidth()).attr("x2",x(n.l)).attr("y1",fy).attr("y2",fy).attr("stroke",Bdr).attr("stroke-width",.5).attr("stroke-dasharray","3,2")}var bg=g.selectAll(".b").data(bars).join("g");bg.append("rect").attr("x",function(d){return x(d.l)}).attr("width",x.bandwidth()).attr("y",function(d){return y(Math.max(d.y0,d.y1))}).attr("height",0).attr("rx",3).attr("fill",function(d){return d.t==="total"?Dk:d.t==="sub"?Dk3:d.t==="fin"?P:"#e5e7eb"}).transition().duration(400).delay(function(_,i){return i*60}).attr("height",function(d){return Math.abs(y(d.y0)-y(d.y1))});bg.append("text").attr("x",function(d){return x(d.l)+x.bandwidth()/2}).attr("y",function(d){return y(Math.max(d.y0,d.y1))-4}).attr("text-anchor","middle").attr("font-size",9).attr("font-weight",700).attr("fill",Tx).attr("opacity",0).text(function(d){return Math.abs(d.v).toLocaleString()}).transition().duration(200).delay(function(_,i){return i*60+350}).attr("opacity",1);g.append("g").attr("transform","translate(0,"+ih+")").call(d3.axisBottom(x).tickSize(0)).selectAll("text").attr("font-size",8).attr("fill",Tx3);g.selectAll(".domain").remove();g.selectAll(".tick line").remove()},[props,ww]);return<div ref={cRef} style={{width:"100%"}}><svg ref={ref} style={{width:"100%",height:"auto"}}/></div>}

